const SHOP_SRC="// src/pages/Shop.jsx \u2014 Boutique (lisitra : suggestions de boutiques + articles par cat\u00e9gorie)\n// Endrika araka ny maquette (sary 1) \u2014 lojika mitovy amin'ny Artists.jsx :\n// recherche live, follow/abonn\u00e9, message d\u00e9di\u00e9, Voir tout, ary fanampiny :\n// panier (localStorage) misy Appel/Message/Supprimer, avatar boutique eo anoloan'ny prix.\nimport { useState, useEffect, useMemo } from 'react';\nimport { useNavigate, useLocation } from 'react-router-dom';\nimport {\n  collection, query, onSnapshot, addDoc, serverTimestamp, orderBy, limit,\n  doc, updateDoc, arrayUnion, arrayRemove, writeBatch, increment, deleteField, deleteDoc\n} from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { useAuth } from '../context/AuthContext';\nimport { parseAppLink } from '../utils/appLink';\nimport { NeonLocation, NeonPlane, NeonPlaneWhite } from '../components/NeonIcons';\nimport ShareModal from '../components/ShareModal';\nimport { downloadMedia } from '../utils/download';\nimport BoostOrderModal from '../components/BoostOrderModal';\nimport { getCart, addToCart, removeFromCart, subscribeCart, firstPhone } from '../utils/cart';\nimport {\n  HiShoppingBag, HiShoppingCart, HiPlus, HiX, HiChevronRight, HiArrowLeft, HiSearch,\n  HiCheck, HiCheckCircle, HiHeart, HiOutlineHeart, HiChat, HiPhone, HiTrash,\n  HiDotsVertical, HiInformationCircle, HiDownload, HiShare, HiFlag, HiLightningBolt\n} from 'react-icons/hi';\n\nconst CATEGORIES = ['V\u00eatements', 'Robes', 'Hauts', 'Pantalons', 'Chaussures', 'Accessoires', '\u00c9lectronique', 'D\u00e9co & Maison', 'V\u00e9hicules', 'Alimentation', 'Beaut\u00e9', 'Autre'];\n\n// Vues : isaina indray mandeha isaky ny session (zaraina amin'ny ShopDetail koa\n// satria module-level, fa samy manana ny Set-ny ny fichier tsirairay \u2014 tsy olana,\n// ny tanjona dia tsy hampitombo imbetsaka ao anatin'ny session iray)\nconst viewedThisSession = new Set();\n\nexport default function Shop() {\n  const { currentUser } = useAuth();\n  const navigate = useNavigate();\n  const location = useLocation();\n\n  // Sokafana ho azy ny panier raha avy amin'ny ic\u00f4ne topbar\n  useEffect(() => {\n    if (location.state?.openCart) setCartOpen(true);\n  }, [location.state]);\n  const [shops, setShops] = useState([]);\n  const [saleItems, setSaleItems] = useState([]);\n  const [open, setOpen] = useState(false);\n  const [name, setName] = useState('');\n  const [category, setCategory] = useState(CATEGORIES[0]);\n  const [creating, setCreating] = useState(false);\n  const [q, setQ] = useState('');\n  const [catFilter, setCatFilter] = useState('Tout');\n  const [showAllShops, setShowAllShops] = useState(false);\n  const [cartOpen, setCartOpen] = useState(false);\n  const [cardMenu, setCardMenu] = useState(null);\n  const [shareItem, setShareItem] = useState(null);\n  const [boostTarget, setBoostTarget] = useState(null);\n\n  // Menus mikatona rehefa scroll na clic ivelany\n  useEffect(() => {\n    const close = () => setCardMenu(null);\n    window.addEventListener('scroll', close, true);\n    document.addEventListener('click', close);\n    return () => { window.removeEventListener('scroll', close, true); document.removeEventListener('click', close); };\n  }, []);\n  const [cart, setCart] = useState(getCart());\n\n  useEffect(() => subscribeCart(setCart), []);\n\n  useEffect(() => {\n    const unsub = onSnapshot(query(collection(db, 'shops')), snap => {\n      const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));\n      list.sort((a, b) => (b.followers?.length || 0) - (a.followers?.length || 0));\n      setShops(list);\n    }, err => console.error('Shops:', err?.message || err));\n    return () => unsub();\n  }, []);\n\n  useEffect(() => {\n    const unsub = onSnapshot(query(collection(db, 'posts'), orderBy('createdAt', 'desc'), limit(150)), snap => {\n      setSaleItems(snap.docs.map(d => ({ id: d.id, ...d.data() })).filter(p => p.isSale && p.shopId && !p.groupId));\n    }, err => console.error('Shop items:', err?.message || err));\n    return () => unsub();\n  }, []);\n\n  // \u2500\u2500 Compteur \"vues\" : mitombo indray mandeha isaky ny session \u2500\u2500\n  useEffect(() => {\n    if (!saleItems.length || !currentUser) return;\n    const fresh = saleItems.filter(p => !viewedThisSession.has(p.id));\n    if (!fresh.length) return;\n    fresh.forEach(p => viewedThisSession.add(p.id));\n    const batch = writeBatch(db);\n    fresh.forEach(p => batch.update(doc(db, 'posts', p.id), { views: increment(1) }));\n    batch.commit().catch(() => {});\n  }, [saleItems.length]); // eslint-disable-line\n\n  const myShops = shops.filter(s => s.admins?.includes(currentUser?.uid));\n  const low = q.trim().toLowerCase();\n\n  const fShops = useMemo(() => !low ? shops : shops.filter(s => (s.name || '').toLowerCase().includes(low)), [shops, low]);\n  const fItems = useMemo(() => {\n    let list = saleItems;\n    if (catFilter !== 'Tout') list = list.filter(p => p.saleCategory === catFilter);\n    if (low) list = list.filter(p => (p.content || '').toLowerCase().includes(low) || (p.shopName || '').toLowerCase().includes(low) || (p.saleCategory || '').toLowerCase().includes(low));\n    return list;\n  }, [saleItems, catFilter, low]);\n\n  const itemCats = useMemo(() => ['Tout', ...Array.from(new Set(saleItems.map(p => p.saleCategory).filter(Boolean)))], [saleItems]);\n\n  async function toggleFollowShop(shopId) {\n    if (!shopId || !currentUser) return;\n    const s = shops.find(x => x.id === shopId);\n    const on = (s?.followers || []).includes(currentUser.uid);\n    try { await updateDoc(doc(db, 'shops', shopId), { followers: on ? arrayRemove(currentUser.uid) : arrayUnion(currentUser.uid) }); } catch (e) { alert('Erreur : ' + (e?.message || e)); }\n  }\n\n  async function toggleHeart(e, p) {\n    e.stopPropagation();\n    if (!currentUser) return;\n    const mine = p.reactions?.[currentUser.uid];\n    try {\n      if (mine) await updateDoc(doc(db, 'posts', p.id), { [`reactions.${currentUser.uid}`]: deleteField() });\n      else await updateDoc(doc(db, 'posts', p.id), { [`reactions.${currentUser.uid}`]: '\u2764\ufe0f' });\n    } catch (err) { console.warn('heart:', err?.message); }\n  }\n\n  // Clic amin'ny card \u2192 compteur clics + detail (endrika sary 3)\n  function openItem(p) {\n    updateDoc(doc(db, 'posts', p.id), { clicks: increment(1) }).catch(() => {});\n    navigate(`/post/${p.id}`);\n  }\n\n  async function createShop() {\n    if (!name.trim()) { alert('Donnez un nom \u00e0 votre boutique'); return; }\n    setCreating(true);\n    try {\n      const ref = await addDoc(collection(db, 'shops'), {\n        name: name.trim(), category, description: '', address: '', team: '', contact: '',\n        photoURL: '', coverURL: '', admins: [currentUser.uid], followers: [],\n        createdBy: currentUser.uid, createdAt: serverTimestamp(),\n      });\n      setOpen(false); setName('');\n      navigate(`/shop/${ref.id}`);\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    setCreating(false);\n  }\n\n  const rowStyle = { display: 'flex', gap: 10, overflowX: 'auto', padding: '2px 0 10px', WebkitOverflowScrolling: 'touch' };\n\n  // \u2500\u2500 Card boutique (suggestions \u2014 sary 1) \u2500\u2500\n  const ShopCard = s => {\n    const on = (s.followers || []).includes(currentUser?.uid);\n    const admin = s.admins?.includes(currentUser?.uid);\n    return (\n      <div key={s.id} className=\"card\" style={{ flex: '0 0 160px', borderRadius: 14, padding: 12, textAlign: 'center' }}>\n        <div onClick={() => navigate(`/shop/${s.id}`)} style={{ width: 74, height: 74, borderRadius: '50%', overflow: 'hidden', margin: '0 auto 8px', background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>\n          {s.photoURL ? <img src={s.photoURL} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <HiShoppingBag size={26} color=\"white\" />}\n        </div>\n        <div style={{ fontWeight: 800, fontSize: 14, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>\n          <span style={{ overflow: 'hidden', textOverflow: 'ellipsis' }}>{s.name}</span>\n          {admin\n            ? <span style={{ fontSize: 9, fontWeight: 800, color: '#F2B300', background: '#FFF6DB', borderRadius: 7, padding: '1px 6px', flexShrink: 0 }}>ADMIN</span>\n            : <HiCheckCircle size={14} color=\"#1877F2\" style={{ flexShrink: 0 }} />}\n        </div>\n        <div style={{ fontSize: 11, color: '#65676B', margin: '1px 0 9px' }}>{(s.followers || []).length} abonn\u00e9s</div>\n        <div style={{ display: 'flex', gap: 6 }}>\n          <button onClick={() => toggleFollowShop(s.id)} className={on ? '' : 'btn-primary'}\n            style={{ flex: 1, borderRadius: 16, padding: '6px 0', fontSize: 12, fontWeight: 700, cursor: 'pointer', border: on ? '1.5px solid #FF2D8D' : 'none',\n              ...(on ? { background: '#fff', color: '#FF2D8D', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 3 } : {}) }}>\n            {on ? <><HiCheck size={13} /> Abonn\u00e9</> : 'Suivre'}\n          </button>\n          <button onClick={() => navigate(`/shop/${s.id}/messages`)} style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 5, background: '#F0F2F5', color: '#050505', border: 'none', borderRadius: 16, padding: '6px 0', fontSize: 12, fontWeight: 600, cursor: 'pointer' }}><NeonPlane size={14} /> Message</button>\n        </div>\n      </div>\n    );\n  };\n\n  return (\n    <div style={{ padding: '14px 12px' }}>\n      {/* \u2500\u2500 En-t\u00eate : Boutique + panier + Cr\u00e9er (sary 1) \u2500\u2500 */}\n      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 4 }}>\n        <h2 style={{ fontWeight: 800, fontSize: 20, display: 'flex', alignItems: 'center', gap: 10 }}>\n          <button onClick={() => navigate(-1)} style={{ background: '#F0F2F5', border: 'none', borderRadius: '50%', width: 34, height: 34, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#050505' }}><HiArrowLeft size={18} /></button>\n          <span className=\"icon-badge-3d\" style={{ width: 34, height: 34, borderRadius: 10, background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)' }}>\n            <HiShoppingBag size={17} color=\"white\" />\n          </span>\n          Boutique\n          <button onClick={() => setCartOpen(true)} title=\"Panier\" style={{ position: 'relative', background: '#F0F2F5', border: 'none', borderRadius: 12, width: 40, height: 40, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#050505' }}>\n            <HiShoppingCart size={21} />\n            {cart.length > 0 && <span style={{ position: 'absolute', top: -5, right: -5, background: '#FF2D8D', color: '#fff', fontSize: 10.5, fontWeight: 800, borderRadius: 10, minWidth: 18, height: 18, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0 4px', border: '2px solid #fff' }}>{cart.length > 9 ? '9+' : cart.length}</span>}\n          </button>\n        </h2>\n        <button onClick={() => setOpen(true)} className=\"btn-primary\" style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '8px 14px', fontSize: 13, borderRadius: 20 }}>\n          <HiPlus size={16} /> Cr\u00e9er\n        </button>\n      </div>\n      <p style={{ fontSize: 12, color: '#65676B', margin: '10px 0 12px' }}>Achetez des produits uniques propos\u00e9s par les boutiques de la communaut\u00e9 Trengo</p>\n\n      {/* \u2500\u2500 Recherche live \u2500\u2500 */}\n      <div style={{ display: 'flex', alignItems: 'center', gap: 8, background: '#fff', border: '1px solid #E4E6EB', borderRadius: 22, padding: '10px 14px', marginBottom: 12 }}>\n        <HiSearch size={18} color=\"#65676B\" />\n        <input value={q} onChange={e => { const l = parseAppLink(e.target.value); if (l) { setQ(''); navigate(l); return; } setQ(e.target.value); }} placeholder=\"Rechercher un article, une boutique\u2026 ou coller un lien\"\n          style={{ flex: 1, border: 'none', outline: 'none', fontSize: 14, background: 'transparent', color: '#050505' }} />\n        {q && <button onClick={() => setQ('')} style={{ background: '#F0F2F5', border: 'none', borderRadius: '50%', width: 24, height: 24, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#65676B' }}><HiX size={14} /></button>}\n      </div>\n\n      {/* \u2500\u2500 Mes pages boutique (mitovy amin'ny \"Mes pages artiste\") \u2500\u2500 */}\n      {myShops.length > 0 && !low && (\n        <div style={{ background: 'linear-gradient(135deg,#FFF0F7,#FFF6E8)', borderRadius: 14, padding: '12px 14px', marginBottom: 12 }}>\n          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>\n            <span style={{ fontWeight: 800, fontSize: 15, color: '#050505', display: 'flex', alignItems: 'center', gap: 7 }}>\n              <HiShoppingBag size={16} color=\"#FF2D8D\" /> Mes pages boutique\n            </span>\n          </div>\n          <div style={{ display: 'flex', gap: 10, overflowX: 'auto' }}>\n            {myShops.map(s => (\n              <div key={s.id} onClick={() => navigate(`/shop/${s.id}`)} style={{ flex: '0 0 auto', display: 'flex', alignItems: 'center', gap: 9, background: '#fff', borderRadius: 12, padding: '8px 12px', boxShadow: '0 1px 3px rgba(0,0,0,.07)', cursor: 'pointer' }}>\n                <div style={{ width: 40, height: 40, borderRadius: '50%', overflow: 'hidden', background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>\n                  {s.photoURL ? <img src={s.photoURL} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <HiShoppingBag size={18} color=\"white\" />}\n                </div>\n                <div>\n                  <div style={{ fontWeight: 800, fontSize: 13, whiteSpace: 'nowrap' }}>{s.name}\n                    <span style={{ marginLeft: 5, fontSize: 9, fontWeight: 700, color: '#F2B300', background: '#FFF6DB', borderRadius: 7, padding: '1px 6px' }}>ADMIN</span>\n                  </div>\n                  <div style={{ fontSize: 11, color: '#65676B' }}>{(s.followers || []).length} abonn\u00e9s</div>\n                </div>\n              </div>\n            ))}\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Suggestions de boutiques + Voir tout (sary 1) \u2500\u2500 */}\n      {fShops.length > 0 && (\n        <>\n          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '6px 0 8px' }}>\n            <span style={{ fontWeight: 800, fontSize: 17, color: '#050505' }}>{low ? 'Boutiques' : 'Suggestions de boutiques'}</span>\n            <button onClick={() => setShowAllShops(v => !v)}\n              style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#FF2D8D', fontWeight: 700, fontSize: 13, display: 'flex', alignItems: 'center', padding: 0 }}>\n              {showAllShops ? 'R\u00e9duire' : 'Voir tout'} <HiChevronRight size={15} style={{ transform: showAllShops ? 'rotate(90deg)' : 'none' }} />\n            </button>\n          </div>\n          {showAllShops\n            ? <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(150px, 1fr))', gap: 10, paddingBottom: 10 }}>{fShops.map(s => ShopCard(s))}</div>\n            : <div style={rowStyle}>{fShops.map(s => ShopCard(s))}</div>}\n        </>\n      )}\n\n      {/* \u2500\u2500 Articles par cat\u00e9gorie (sary 1) \u2500\u2500 */}\n      {saleItems.length > 0 && (\n        <>\n          <div style={{ padding: '8px 0 8px' }}>\n            <span style={{ fontWeight: 800, fontSize: 17, color: '#050505' }}>Articles par cat\u00e9gorie</span>\n          </div>\n          <div style={{ display: 'flex', gap: 8, overflowX: 'auto', padding: '0 0 10px', scrollbarWidth: 'none' }}>\n            {itemCats.map(cat => (\n              <button key={cat} onClick={() => setCatFilter(cat)}\n                style={{ flex: '0 0 auto', padding: '8px 18px', borderRadius: 20, border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13, fontWeight: 700,\n                  background: catFilter === cat ? 'linear-gradient(145deg,#FF6FA5,#FF2D8D)' : '#fff',\n                  boxShadow: catFilter === cat ? 'none' : '0 1px 3px rgba(0,0,0,.08)',\n                  color: catFilter === cat ? 'white' : '#65676B', whiteSpace: 'nowrap' }}>\n                {cat}\n              </button>\n            ))}\n          </div>\n\n          {fItems.length === 0 && <p style={{ padding: 24, textAlign: 'center', color: '#65676B', fontSize: 13 }}>Aucun article dans cette cat\u00e9gorie.</p>}\n\n          {/* Grille produits (sary 1) : sary + \u2764\ufe0f, anarana, prix + avatar boutique, lieu, Message + panier */}\n          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))', gap: 10, paddingBottom: 14 }}>\n            {fItems.map(p => {\n              const myHeart = !!p.reactions?.[currentUser?.uid];\n              return (\n                <div key={p.id} onClick={() => openItem(p)} className=\"card\" style={{ overflow: 'hidden', cursor: 'pointer', borderRadius: 14, boxShadow: '0 1px 4px rgba(0,0,0,.08)', display: 'flex', flexDirection: 'column' }}>\n                  <div style={{ position: 'relative' }}>\n                    {p.mediaURL\n                      ? <img src={p.mediaURL} alt=\"\" style={{ width: '100%', aspectRatio: '1', objectFit: 'cover', display: 'block' }} />\n                      : <div style={{ width: '100%', aspectRatio: '1', background: '#F0F2F5', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><HiShoppingBag size={34} color=\"#CED0D4\" /></div>}\n                    <button onClick={e => toggleHeart(e, p)} style={{ position: 'absolute', top: 8, right: 8, width: 32, height: 32, borderRadius: '50%', background: 'rgba(255,255,255,.95)', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 1px 5px rgba(0,0,0,.15)' }}>\n                      {myHeart ? <HiHeart size={18} color=\"#FF2D8D\" /> : <HiOutlineHeart size={18} color=\"#050505\" />}\n                    </button>\n                    {p.uid === currentUser?.uid && (\n                      <button onClick={e => { e.stopPropagation(); setBoostTarget({ type:'post', id:p.id, ownerUid:p.uid, title:(p.content||'').slice(0,60)||'Mon article', thumbnailURL:p.mediaURL||'' }); }}\n                        title=\"Booster\" style={{ position: 'absolute', bottom: 8, right: 8, width: 30, height: 30, borderRadius: '50%', background: 'linear-gradient(135deg,#1B84FF,#1877F2)', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 2px 8px rgba(24,119,242,.5)' }}>\n                        <HiLightningBolt size={16} color=\"white\" />\n                      </button>\n                    )}\n                    <div style={{ position: 'absolute', top: 8, left: 8 }} onClick={e => e.stopPropagation()}>\n                      <button onClick={() => setCardMenu(cardMenu === p.id ? null : p.id)}\n                        style={{ width: 32, height: 32, borderRadius: '50%', background: 'rgba(255,255,255,.95)', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 1px 5px rgba(0,0,0,.15)', color: '#050505' }}>\n                        <HiDotsVertical size={16} />\n                      </button>\n                      {cardMenu === p.id && (\n                        <div style={{ position: 'absolute', top: '110%', left: 0, background: 'white', border: '1px solid #E4E6EB', borderRadius: 12, boxShadow: '0 6px 22px rgba(0,0,0,.16)', minWidth: 165, zIndex: 60, overflow: 'hidden' }}>\n                          <button onClick={() => { setCardMenu(null); navigate(`/post/${p.id}`); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, fontWeight: 400, color: '#050505', borderBottom: '1px solid #F0F2F5' }}><HiInformationCircle size={16} color=\"#1877F2\" /> Informations</button>\n                          {p.mediaURL && <button onClick={() => { setCardMenu(null); downloadMedia(p.mediaURL, p.mediaType || 'image', p.content || 'article'); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, fontWeight: 400, color: '#050505', borderBottom: '1px solid #F0F2F5' }}><HiDownload size={16} color=\"#12A48D\" /> T\u00e9l\u00e9charger</button>}\n                          <button onClick={() => { setCardMenu(null); setShareItem(p); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, fontWeight: 400, color: '#050505', borderBottom: '1px solid #F0F2F5' }}><HiShare size={16} color=\"#7A2DFF\" /> Partager</button>\n                          {p.uid === currentUser?.uid\n                            ? <button onClick={async () => { setCardMenu(null); if (window.confirm('Supprimer cet article ?')) { try { await deleteDoc(doc(db, 'posts', p.id)); } catch (e) { alert('Erreur : ' + (e?.message || e)); } } }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, fontWeight: 400, color: '#FF2D8D' }}><HiTrash size={16} /> Supprimer</button>\n                            : <button onClick={async () => { setCardMenu(null); if (!window.confirm('Signaler cet article aux administrateurs ?')) return; try { await addDoc(collection(db, 'reports'), { type: 'post', targetId: p.id, targetUid: p.uid, targetAuthor: p.shopName || p.authorName || '', reportedBy: currentUser.uid, createdAt: serverTimestamp(), status: 'pending' }); alert('Signalement envoy\u00e9. Merci.'); } catch (e) { alert('Erreur : ' + (e?.message || e)); } }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, fontWeight: 400, color: '#050505' }}><HiFlag size={16} color=\"#F2B300\" /> Signaler</button>}\n                        </div>\n                      )}\n                    </div>\n                  </div>\n                  <div style={{ padding: '9px 10px 11px', display: 'flex', flexDirection: 'column', flex: 1 }}>\n                    <p style={{ fontSize: 13, fontWeight: 700, lineHeight: 1.35, overflow: 'hidden', textOverflow: 'ellipsis', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical' }}>{p.content}</p>\n                    {/* Prix + profil boutique en face (sary 1) */}\n                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 6, marginTop: 5 }}>\n                      <span style={{ fontWeight: 800, fontSize: 15, color: '#FF2D8D' }}>{p.price ? `${Number(p.price).toLocaleString()} Ar` : '\u00c0 discuter'}</span>\n                      <div onClick={e => { e.stopPropagation(); navigate(`/shop/${p.shopId}`); }} title={p.shopName}\n                        style={{ width: 28, height: 28, borderRadius: '50%', overflow: 'hidden', background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, cursor: 'pointer', border: '2px solid #FFE3EF' }}>\n                        {p.shopPhoto ? <img src={p.shopPhoto} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <HiShoppingBag size={13} color=\"white\" />}\n                      </div>\n                    </div>\n                    {p.lieu && <p style={{ fontSize: 11.5, color: '#65676B', display: 'flex', alignItems: 'center', gap: 4, marginTop: 3 }}><NeonLocation size={12} /> <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{p.lieu}</span></p>}\n                    <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginTop: 'auto', paddingTop: 8 }}>\n                      <button onClick={e => { e.stopPropagation(); navigate(`/shop/${p.shopId}/messages`); }}\n                        style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 5, background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', border: 'none', borderRadius: 18, padding: '8px 0', fontSize: 12.5, fontWeight: 700, color: '#fff', cursor: 'pointer' }}>\n                        <NeonPlaneWhite size={14} /> Message\n                      </button>\n                      <button onClick={e => { e.stopPropagation(); const ok = addToCart(p); alert(ok ? 'Article ajout\u00e9 au panier \ud83d\uded2' : 'Cet article est d\u00e9j\u00e0 dans votre panier'); }}\n                        title=\"Ajouter au panier\"\n                        style={{ width: 36, height: 34, display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#fff', border: '1.5px solid #FF2D8D', borderRadius: 18, cursor: 'pointer', color: '#FF2D8D', flexShrink: 0 }}>\n                        <HiShoppingCart size={16} />\n                      </button>\n                    </div>\n                  </div>\n                </div>\n              );\n            })}\n          </div>\n        </>\n      )}\n\n      {/* \u2500\u2500 Vide \u2500\u2500 */}\n      {fShops.length === 0 && fItems.length === 0 && (\n        <div className=\"card\" style={{ padding: 30, textAlign: 'center' }}>\n          <p style={{ fontWeight: 700, marginBottom: 4 }}>{low ? 'Aucun r\u00e9sultat' : 'Aucune boutique pour le moment'}</p>\n          <p style={{ fontSize: 13, color: '#65676B' }}>{low ? 'Essayez un autre mot-cl\u00e9' : 'Cr\u00e9ez la premi\u00e8re boutique de la communaut\u00e9 !'}</p>\n        </div>\n      )}\n\n      {/* \u2500\u2500 PANIER (localStorage) : Supprimer / Appel / Message \u2500\u2500 */}\n      {cartOpen && (\n        <div onClick={() => setCartOpen(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.55)', zIndex: 400, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }}>\n          <div onClick={e => e.stopPropagation()} style={{ background: '#fff', borderRadius: '20px 20px 0 0', width: '100%', maxWidth: 520, maxHeight: '82vh', overflowY: 'auto', padding: '14px 14px 26px' }}>\n            <div style={{ width: 40, height: 4, borderRadius: 2, background: '#CED0D4', margin: '0 auto 12px' }} />\n            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>\n              <span style={{ fontWeight: 800, fontSize: 18, display: 'flex', alignItems: 'center', gap: 8 }}>\n                <HiShoppingCart size={20} color=\"#FF2D8D\" /> Mon panier\n                <span style={{ fontSize: 12, color: '#65676B', fontWeight: 600 }}>{cart.length} article{cart.length > 1 ? 's' : ''}</span>\n              </span>\n              <button onClick={() => setCartOpen(false)} style={{ background: '#F0F2F5', border: 'none', borderRadius: '50%', width: 34, height: 34, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#65676B' }}><HiX size={18} /></button>\n            </div>\n\n            {cart.length === 0 && (\n              <div style={{ padding: 34, textAlign: 'center' }}>\n                <HiShoppingCart size={40} color=\"#CED0D4\" style={{ marginBottom: 8 }} />\n                <p style={{ fontWeight: 700, marginBottom: 4 }}>Votre panier est vide</p>\n                <p style={{ fontSize: 13, color: '#65676B' }}>Ajoutez des articles pour contacter les boutiques facilement.</p>\n              </div>\n            )}\n\n            {cart.map(item => (\n              <div key={item.id} className=\"card\" style={{ display: 'flex', gap: 10, padding: 10, marginBottom: 10, borderRadius: 14, boxShadow: '0 1px 4px rgba(0,0,0,.07)' }}>\n                <div onClick={() => { setCartOpen(false); navigate(`/post/${item.id}`); }} style={{ width: 72, height: 72, borderRadius: 12, overflow: 'hidden', background: '#F0F2F5', flexShrink: 0, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n                  {item.mediaURL ? <img src={item.mediaURL} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <HiShoppingBag size={24} color=\"#CED0D4\" />}\n                </div>\n                <div style={{ flex: 1, minWidth: 0 }}>\n                  <p style={{ fontSize: 13, fontWeight: 700, lineHeight: 1.3, overflow: 'hidden', textOverflow: 'ellipsis', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical' }}>{item.name}</p>\n                  <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginTop: 2 }}>\n                    <span style={{ fontWeight: 800, fontSize: 14, color: '#FF2D8D' }}>{item.price ? `${Number(item.price).toLocaleString()} Ar` : '\u00c0 discuter'}</span>\n                    <span onClick={() => { setCartOpen(false); navigate(`/shop/${item.shopId}`); }} style={{ fontSize: 11, color: '#65676B', cursor: 'pointer', textDecoration: 'underline', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{item.shopName}</span>\n                  </div>\n                  <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginTop: 8, flexWrap: 'wrap' }}>\n                    {firstPhone(item.contact) && (\n                      <a href={`tel:${firstPhone(item.contact)}`} onClick={e => e.stopPropagation()}\n                        style={{ display: 'flex', alignItems: 'center', gap: 4, background: 'linear-gradient(145deg,#3DD9C4,#12A48D)', borderRadius: 16, padding: '6px 12px', color: '#fff', fontSize: 12, fontWeight: 700, textDecoration: 'none' }}>\n                        <HiPhone size={13} /> Appel\n                      </a>\n                    )}\n                    <button onClick={() => { setCartOpen(false); navigate(`/shop/${item.shopId}/messages`); }}\n                      style={{ display: 'flex', alignItems: 'center', gap: 4, background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', border: 'none', borderRadius: 16, padding: '6px 12px', color: '#fff', fontSize: 12, fontWeight: 700, cursor: 'pointer' }}>\n                      <HiChat size={13} /> Message\n                    </button>\n                    <button onClick={() => removeFromCart(item.id)}\n                      style={{ display: 'flex', alignItems: 'center', gap: 4, background: '#F0F2F5', border: 'none', borderRadius: 16, padding: '6px 12px', color: '#FF2D8D', fontSize: 12, fontWeight: 700, cursor: 'pointer' }}>\n                      <HiTrash size={13} /> Supprimer\n                    </button>\n                  </div>\n                </div>\n              </div>\n            ))}\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Modale cr\u00e9ation \u2500\u2500 */}\n      {open && (\n        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 400, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }} onClick={() => setOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background: 'white', borderRadius: '20px 20px 0 0', padding: 20, width: '100%', maxWidth: 480 }}>\n            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>\n              <h3 style={{ fontWeight: 800, color: '#FF2D8D', fontSize: 16 }}>Cr\u00e9er une boutique</h3>\n              <button onClick={() => setOpen(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#65676B' }}><HiX size={20} /></button>\n            </div>\n            <input className=\"input\" placeholder=\"Nom de la boutique\" value={name} onChange={e => setName(e.target.value)} maxLength={80} style={{ marginBottom: 10 }} />\n            <select value={category} onChange={e => setCategory(e.target.value)} className=\"input\" style={{ marginBottom: 14 }}>\n              {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}\n            </select>\n            <button onClick={createShop} disabled={creating} className=\"btn-primary\" style={{ width: '100%', padding: '12px 0', fontSize: 15 }}>\n              {creating ? 'Cr\u00e9ation...' : 'Cr\u00e9er ma boutique \u2728'}\n            </button>\n            <p style={{ fontSize: 11, color: '#65676B', marginTop: 8, textAlign: 'center' }}>Vous serez administrateur de cette boutique.</p>\n          </div>\n        </div>\n      )}\n      {shareItem && <ShareModal post={shareItem} onClose={() => setShareItem(null)} />}\n      {boostTarget && <BoostOrderModal target={boostTarget} onClose={() => setBoostTarget(null)} />}\n    </div>\n  );\n}\n";
const ARTISTS_SRC="// src/pages/Artists.jsx \u2014 Canaux Artiste : recherche live, mes pages, musiques, clips\nimport { useState, useEffect, useRef, useMemo } from 'react';\nimport { useNavigate } from 'react-router-dom';\nimport { collection, query, onSnapshot, addDoc, serverTimestamp, orderBy, limit, doc, updateDoc, arrayUnion, arrayRemove } from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { useAuth } from '../context/AuthContext';\nimport { parseAppLink } from '../utils/appLink';\nimport { NeonMic } from '../components/NeonIcons';\nimport { HiPlus, HiX, HiChevronRight, HiArrowLeft, HiSearch, HiDotsVertical, HiCheckCircle, HiCheck, HiInformationCircle, HiDownload, HiLightningBolt, HiShare, HiTrash, HiFlag } from 'react-icons/hi';\nimport { downloadMedia } from '../utils/download';\nimport ShareModal from '../components/ShareModal';\nimport BoostOrderModal from '../components/BoostOrderModal';\nimport { doc as fsDoc, deleteDoc, addDoc as fsAddDoc, serverTimestamp as fsServerTimestamp, collection as fsCollection } from 'firebase/firestore';\n\nconst GRADS = [['#FF6FA5', '#FF2D8D'], ['#A66BFF', '#7A2DFF'], ['#3DBEFF', '#1877F2']];\n\nfunction waveBars(seed, n = 40) {\n  let s = 0; for (let i = 0; i < seed.length; i++) s = (s * 31 + seed.charCodeAt(i)) % 100000;\n  const rnd = () => { s = (s * 9301 + 49297) % 233280; return s / 233280; };\n  return Array.from({ length: n }, (_, i) => 8 + Math.abs(Math.sin(i * 0.4 + s)) * 36 + rnd() * 12);\n}\n\nfunction fmtDur(sec) {\n  if (!sec || !isFinite(sec)) return '';\n  const m = Math.floor(sec / 60), s = Math.floor(sec % 60);\n  return m + ':' + String(s).padStart(2, '0');\n}\n\nfunction TrackCard({ track, index, playing, onToggle, onArtist, onBoost, onShare, currentUid }) {\n  const [dur, setDur] = useState('');\n  const [menuOpen, setMenuOpen] = useState(false);\n  const bars = useRef(waveBars(track.id || String(index)));\n  const grad = GRADS[index % 3];\n  const navigate = useNavigate();\n  const isOwn = track.uid && currentUid && track.uid === currentUid;\n  useEffect(() => {\n    if (!track.mediaURL) return;\n    const a = new Audio(); a.preload = 'metadata'; a.src = track.mediaURL;\n    const on = () => setDur(fmtDur(a.duration));\n    a.addEventListener('loadedmetadata', on);\n    return () => { a.removeEventListener('loadedmetadata', on); a.src = ''; };\n  }, [track.mediaURL]);\n  async function removeTrack() {\n    if (!window.confirm('Supprimer ce titre ?')) return;\n    try { await deleteDoc(fsDoc(db, 'posts', track.id)); } catch (e) { alert('Erreur : ' + (e?.message || e)); }\n  }\n  async function reportTrack() {\n    if (!window.confirm('Signaler ce titre aux administrateurs ?')) return;\n    try { await fsAddDoc(fsCollection(db, 'reports'), { type:'post', targetId:track.id, targetUid:track.uid, targetAuthor:track.artistName||'', reportedBy:currentUid, createdAt:fsServerTimestamp(), status:'pending' }); alert('Signalement envoy\u00e9. Merci.'); } catch (e) { alert('Erreur : ' + (e?.message || e)); }\n  }\n  return (\n    <div style={{ flex: '0 0 180px', background: '#0c0c12', borderRadius: 14, overflow: 'hidden' }}>\n      <div style={{ position: 'relative', height: 110, display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' }}>\n        <div onClick={() => onArtist?.(track.artistId)} style={{ position: 'absolute', top: 8, left: 8, width: 34, height: 34, borderRadius: '50%', overflow: 'hidden', border: '2px solid rgba(255,255,255,.85)', zIndex: 3, cursor: 'pointer', background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n          {track.artistPhoto ? <img src={track.artistPhoto} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <NeonMic size={16} color=\"white\" />}\n        </div>\n        <div style={{ position: 'absolute', top: 8, right: 8, zIndex: 4 }} onClick={e => e.stopPropagation()}>\n          <button onClick={() => setMenuOpen(p => !p)} style={{ width: 28, height: 28, borderRadius: '50%', background: 'rgba(0,0,0,.5)', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white' }}>\n            <HiDotsVertical size={15} />\n          </button>\n          {menuOpen && (\n            <div style={{ position: 'absolute', top: '110%', right: 0, background: 'white', border: '1px solid #E4E6EB', borderRadius: 12, boxShadow: '0 6px 22px rgba(0,0,0,.25)', minWidth: 175, zIndex: 60, overflow: 'hidden' }}>\n              <button onClick={() => { setMenuOpen(false); navigate(`/post/${track.id}`); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, color: '#050505', borderBottom: '1px solid #F0F2F5' }}><HiInformationCircle size={16} color=\"#1877F2\" /> Informations</button>\n              {track.mediaURL && <button onClick={() => { setMenuOpen(false); downloadMedia(track.mediaURL, 'audio', track.songTitle || 'titre'); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, color: '#050505', borderBottom: '1px solid #F0F2F5' }}><HiDownload size={16} color=\"#12A48D\" /> T\u00e9l\u00e9charger</button>}\n              {isOwn && <button onClick={() => { setMenuOpen(false); onBoost?.({ type:'post', id:track.id, ownerUid:track.uid, title:track.songTitle||track.artistName||'Mon titre', thumbnailURL:track.thumbURL||track.mediaURL||'' }); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, color: '#050505', borderBottom: '1px solid #F0F2F5' }}><HiLightningBolt size={16} color=\"#a855f7\" /> Booster</button>}\n              <button onClick={() => { setMenuOpen(false); onShare?.(track); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, color: '#050505', borderBottom: isOwn ? '1px solid #F0F2F5' : 'none' }}><HiShare size={16} color=\"#7A2DFF\" /> Partager</button>\n              {isOwn\n                ? <button onClick={() => { setMenuOpen(false); removeTrack(); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, color: '#FF2D8D' }}><HiTrash size={16} /> Supprimer</button>\n                : <button onClick={() => { setMenuOpen(false); reportTrack(); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 14px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 13.5, color: '#050505' }}><HiFlag size={16} color=\"#F2B300\" /> Signaler</button>}\n            </div>\n          )}\n        </div>\n        {track.thumbURL && <div style={{ position: 'absolute', inset: 0, backgroundImage: 'url(' + track.thumbURL + ')', backgroundSize: 'cover', backgroundPosition: 'center', filter: 'brightness(.45)', zIndex: 0 }} />}\n        <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 2, padding: '0 10px', zIndex: 1 }}>\n          {bars.current.map((h, i) => <div key={i} style={{ width: 3, height: h, borderRadius: 3, background: i / bars.current.length < 0.5 ? grad[0] : grad[1], opacity: playing ? 0.95 : 0.7 }} />)}\n        </div>\n        <div onClick={() => onToggle?.(track)} style={{ position: 'relative', zIndex: 2, width: 42, height: 42, borderRadius: '50%', background: 'rgba(0,0,0,.5)', border: '2px solid rgba(255,255,255,.92)', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>\n          {playing ? <svg width=\"16\" height=\"18\" viewBox=\"0 0 24 24\" fill=\"#fff\"><rect x=\"6\" y=\"4\" width=\"4\" height=\"16\" rx=\"1.5\" /><rect x=\"14\" y=\"4\" width=\"4\" height=\"16\" rx=\"1.5\" /></svg>\n                   : <svg width=\"16\" height=\"18\" viewBox=\"0 0 24 24\" fill=\"#fff\" style={{ marginLeft: 3 }}><path d=\"M6 4l14 8-14 8z\" /></svg>}\n        </div>\n      </div>\n      <div style={{ display: 'flex', alignItems: 'flex-end', justifyContent: 'space-between', padding: '8px 10px 10px' }}>\n        <div style={{ minWidth: 0 }}>\n          <div style={{ fontWeight: 800, fontSize: 13, color: '#fff', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{track.songTitle || 'Sans titre'}</div>\n          <div style={{ fontSize: 11, color: '#b9b9c2', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{track.artistName}</div>\n        </div>\n        {dur && <div style={{ fontSize: 11, color: '#e6e6ea', fontWeight: 600, flexShrink: 0, marginLeft: 6 }}>{dur}</div>}\n      </div>\n    </div>\n  );\n}\n\nexport default function Artists() {\n  const { currentUser } = useAuth();\n  const navigate = useNavigate();\n  const [artists, setArtists] = useState([]);\n  const [media, setMedia] = useState([]);\n  const [open, setOpen] = useState(false);\n  const [name, setName] = useState('');\n  const [creating, setCreating] = useState(false);\n  const [q, setQ] = useState('');\n  const [boostTarget, setBoostTarget] = useState(null);\n  const [shareItem, setShareItem] = useState(null);\n\n  const audioRef = useRef(null);\n  const [playingId, setPlayingId] = useState(null);\n  function toggleTrack(t) {\n    if (!t?.mediaURL) return;\n    if (!audioRef.current) audioRef.current = new Audio();\n    const a = audioRef.current;\n    if (playingId === t.id) { a.pause(); setPlayingId(null); return; }\n    a.src = t.mediaURL; a.onended = () => setPlayingId(null);\n    a.play().catch(() => {});\n    setPlayingId(t.id);\n  }\n\n  useEffect(() => {\n    const unsub = onSnapshot(query(collection(db, 'artists')), snap => {\n      const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));\n      list.sort((a, b) => (b.followers?.length || 0) - (a.followers?.length || 0));\n      setArtists(list);\n    }, err => console.error('Artists:', err?.message || err));\n    return () => unsub();\n  }, []);\n\n  useEffect(() => {\n    const unsub = onSnapshot(query(collection(db, 'posts'), orderBy('createdAt', 'desc'), limit(120)), snap => {\n      setMedia(snap.docs.map(d => ({ id: d.id, ...d.data() })).filter(p => p.isMusic));\n    }, err => console.error('Media:', err?.message || err));\n    return () => unsub();\n  }, []);\n\n  const myPages = artists.filter(a => a.admins?.includes(currentUser?.uid));\n  const low = q.trim().toLowerCase();\n\n  const fArtists = useMemo(() => !low ? artists : artists.filter(a => a.name?.toLowerCase().includes(low)), [artists, low]);\n  const fTracks  = useMemo(() => {\n    const t = media.filter(m => m.mediaType === 'audio');\n    return !low ? t : t.filter(m => m.songTitle?.toLowerCase().includes(low) || m.artistName?.toLowerCase().includes(low) || m.genre?.toLowerCase().includes(low));\n  }, [media, low]);\n  const fVideos  = useMemo(() => {\n    const v = media.filter(m => m.mediaType === 'video');\n    return !low ? v : v.filter(m => m.songTitle?.toLowerCase().includes(low) || m.artistName?.toLowerCase().includes(low) || m.content?.toLowerCase().includes(low));\n  }, [media, low]);\n\n  async function toggleFollowArtist(artistId) {\n    if (!artistId || !currentUser) return;\n    const a = artists.find(x => x.id === artistId);\n    const on = (a?.followers || []).includes(currentUser.uid);\n    try { await updateDoc(doc(db, 'artists', artistId), { followers: on ? arrayRemove(currentUser.uid) : arrayUnion(currentUser.uid) }); } catch (e) { alert('Erreur : ' + (e?.message || e)); }\n  }\n\n  async function createArtist() {\n    if (!name.trim()) { alert('Donnez un nom \u00e0 votre canal artiste'); return; }\n    setCreating(true);\n    try {\n      const ref = await addDoc(collection(db, 'artists'), {\n        name: name.trim(), bio: '', label: '', manager: '', address: '', contact: '', website: '',\n        photoURL: '', coverURL: '', admins: [currentUser.uid], followers: [],\n        createdBy: currentUser.uid, createdAt: serverTimestamp(),\n      });\n      setOpen(false); setName('');\n      navigate(`/artists/${ref.id}`);\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    setCreating(false);\n  }\n\n  const rowStyle = { display: 'flex', gap: 10, overflowX: 'auto', padding: '2px 0 10px', WebkitOverflowScrolling: 'touch' };\n  const secHd = (title, count, type) => (\n    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '6px 0 8px' }}>\n      <span style={{ fontWeight: 800, fontSize: 17, color: '#050505' }}>{title}</span>\n      {count > 0 && (\n        <button onClick={() => navigate(`/artists/all/${type}`)}\n          style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#FF2D8D', fontWeight: 700, fontSize: 13, display: 'flex', alignItems: 'center', padding: 0 }}>\n          Voir tout <HiChevronRight size={15} />\n        </button>\n      )}\n    </div>\n  );\n\n  return (\n    <div style={{ padding: '14px 12px' }}>\n      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 4 }}>\n        <h2 style={{ fontWeight: 800, fontSize: 20, display: 'flex', alignItems: 'center', gap: 10 }}>\n          <button onClick={() => navigate(-1)} style={{ background: '#F0F2F5', border: 'none', borderRadius: '50%', width: 34, height: 34, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#050505' }}><HiArrowLeft size={18} /></button>\n          <span className=\"icon-badge-3d\" style={{ width: 34, height: 34, borderRadius: 10, background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)' }}>\n            <NeonMic size={17} color=\"white\" />\n          </span>\n          Artistes\n        </h2>\n        <button onClick={() => setOpen(true)} className=\"btn-primary\" style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '8px 14px', fontSize: 13, borderRadius: 20 }}>\n          <HiPlus size={16} /> Cr\u00e9er\n        </button>\n      </div>\n      <p style={{ fontSize: 12, color: '#65676B', margin: '10px 0 12px' }}>D\u00e9couvrez les canaux musique/vid\u00e9o des cr\u00e9ateurs de Trengo</p>\n\n      {/* Recherche live */}\n      <div style={{ display: 'flex', alignItems: 'center', gap: 8, background: '#fff', border: '1px solid #E4E6EB', borderRadius: 22, padding: '10px 14px', marginBottom: 12 }}>\n        <HiSearch size={18} color=\"#65676B\" />\n        <input value={q} onChange={e => { const l = parseAppLink(e.target.value); if (l) { setQ(''); navigate(l); return; } setQ(e.target.value); }} placeholder=\"Rechercher une chanson, un artiste\u2026 ou coller un lien\"\n          style={{ flex: 1, border: 'none', outline: 'none', fontSize: 14, background: 'transparent', color: '#050505' }} />\n        {q && <button onClick={() => setQ('')} style={{ background: '#F0F2F5', border: 'none', borderRadius: '50%', width: 24, height: 24, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#65676B' }}><HiX size={14} /></button>}\n      </div>\n\n      {/* Mes pages artiste \u2014 section s\u00e9par\u00e9e */}\n      {myPages.length > 0 && !low && (\n        <div style={{ background: 'linear-gradient(135deg,#FFF0F7,#F3ECFF)', borderRadius: 14, padding: '12px 14px', marginBottom: 12 }}>\n          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>\n            <span style={{ fontWeight: 800, fontSize: 15, color: '#050505', display: 'flex', alignItems: 'center', gap: 7 }}>\n              <NeonMic size={16} color=\"#FF2D8D\" /> Mes pages artiste\n            </span>\n          </div>\n          <div style={{ display: 'flex', gap: 10, overflowX: 'auto' }}>\n            {myPages.map(a => (\n              <div key={a.id} onClick={() => navigate(`/artists/${a.id}`)} style={{ flex: '0 0 auto', display: 'flex', alignItems: 'center', gap: 9, background: '#fff', borderRadius: 12, padding: '8px 12px', boxShadow: '0 1px 3px rgba(0,0,0,.07)', cursor: 'pointer' }}>\n                <div style={{ width: 40, height: 40, borderRadius: '50%', overflow: 'hidden', background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>\n                  {a.photoURL ? <img src={a.photoURL} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <NeonMic size={18} color=\"white\" />}\n                </div>\n                <div>\n                  <div style={{ fontWeight: 800, fontSize: 13, whiteSpace: 'nowrap' }}>{a.name}\n                    <span style={{ marginLeft: 5, fontSize: 9, fontWeight: 700, color: '#F2B300', background: '#FFF6DB', borderRadius: 7, padding: '1px 6px' }}>ADMIN</span>\n                  </div>\n                  <div style={{ fontSize: 11, color: '#65676B' }}>{(a.followers || []).length} abonn\u00e9s</div>\n                </div>\n              </div>\n            ))}\n          </div>\n        </div>\n      )}\n\n      {/* Suggestions d'artistes */}\n      {fArtists.length > 0 && (\n        <>\n          {secHd(low ? 'Artistes' : \"Suggestions d'artistes\", fArtists.length, 'artists')}\n          <div style={rowStyle}>\n            {fArtists.map(a => (\n              <div key={a.id} className=\"card\" style={{ flex: '0 0 150px', borderRadius: 14, padding: 12, textAlign: 'center' }}>\n                <div onClick={() => navigate(`/artists/${a.id}`)} style={{ width: 74, height: 74, borderRadius: '50%', overflow: 'hidden', margin: '0 auto 8px', background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>\n                  {a.photoURL ? <img src={a.photoURL} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <NeonMic size={26} color=\"white\" />}\n                </div>\n                <div style={{ fontWeight: 800, fontSize: 14, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 3, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>\n                  {a.name} <HiCheckCircle size={14} color=\"#1877F2\" />\n                </div>\n                <div style={{ fontSize: 11, color: '#65676B', margin: '1px 0 9px' }}>{(a.followers || []).length} abonn\u00e9s</div>\n                <div style={{ display: 'flex', gap: 6 }}>\n                  {(() => { const on = (a.followers || []).includes(currentUser?.uid);\n                    return (\n                      <button onClick={() => toggleFollowArtist(a.id)} className={on ? '' : 'btn-primary'}\n                        style={{ flex: 1, borderRadius: 16, padding: '6px 0', fontSize: 12, fontWeight: 700, cursor: 'pointer', border: 'none',\n                          ...(on ? { background: '#F0F2F5', color: '#050505', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 3 } : {}) }}>\n                        {on ? <><HiCheck size={13} /> Abonn\u00e9</> : 'Suivre'}\n                      </button>\n                    ); })()}\n                  <button onClick={() => navigate(`/artists/${a.id}/messages`)} style={{ flex: 1, background: '#F0F2F5', color: '#050505', border: 'none', borderRadius: 16, padding: '6px 0', fontSize: 12, fontWeight: 600, cursor: 'pointer' }}>Message</button>\n                </div>\n              </div>\n            ))}\n          </div>\n        </>\n      )}\n\n      {/* Musiques pour vous */}\n      {fTracks.length > 0 && (\n        <>\n          {secHd('Musiques pour vous', fTracks.length, 'music')}\n          <div style={rowStyle}>\n            {fTracks.map((t, i) => (\n              <TrackCard key={t.id} track={t} index={i} playing={playingId === t.id} onToggle={toggleTrack} onArtist={aid => aid && navigate(`/artists/${aid}`)} onBoost={setBoostTarget} onShare={setShareItem} currentUid={currentUser?.uid} />\n            ))}\n          </div>\n        </>\n      )}\n\n      {/* Vid\u00e9os / Clips */}\n      {fVideos.length > 0 && (\n        <>\n          {secHd('Vid\u00e9os / Clips / Articles', fVideos.length, 'videos')}\n          <div style={{ display: 'grid', gridAutoFlow: 'column', gridTemplateRows: fVideos.length > 1 ? '1fr 1fr' : '1fr', gap: 10, overflowX: 'auto', padding: '2px 0 12px', WebkitOverflowScrolling: 'touch' }}>\n            {fVideos.map(v => (\n              <div key={v.id} onClick={() => navigate(`/post/${v.id}`)} style={{ width: 230, cursor: 'pointer' }}>\n                <div style={{ position: 'relative', width: '100%', height: 120, borderRadius: 12, overflow: 'hidden', background: '#000' }}>\n                  {v.thumbURL ? <img src={v.thumbURL} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <video src={v.mediaURL} style={{ width: '100%', height: '100%', objectFit: 'cover' }} muted />}\n                </div>\n                <div style={{ display: 'flex', gap: 8, padding: '6px 2px 0' }}>\n                  <div style={{ width: 30, height: 30, borderRadius: '50%', overflow: 'hidden', flexShrink: 0, background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n                    {v.artistPhoto ? <img src={v.artistPhoto} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <NeonMic size={14} color=\"white\" />}\n                  </div>\n                  <div style={{ minWidth: 0 }}>\n                    <div style={{ fontWeight: 700, fontSize: 13, lineHeight: 1.2, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{v.songTitle || v.content || 'Vid\u00e9o'}</div>\n                    <div style={{ fontSize: 11, color: '#65676B', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{v.artistName}</div>\n                  </div>\n                </div>\n              </div>\n            ))}\n          </div>\n        </>\n      )}\n\n      {/* Vide */}\n      {fArtists.length === 0 && fTracks.length === 0 && fVideos.length === 0 && (\n        <div className=\"card\" style={{ padding: 30, textAlign: 'center' }}>\n          <p style={{ fontWeight: 700, marginBottom: 4 }}>{low ? 'Aucun r\u00e9sultat' : 'Aucun canal artiste pour le moment'}</p>\n          <p style={{ fontSize: 13, color: '#65676B' }}>{low ? 'Essayez un autre mot-cl\u00e9' : 'Cr\u00e9ez le v\u00f4tre et publiez vos sons !'}</p>\n        </div>\n      )}\n\n      {/* Modale cr\u00e9ation */}\n      {open && (\n        <div onClick={() => setOpen(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.55)', zIndex: 300, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }}>\n          <div onClick={e => e.stopPropagation()} style={{ background: '#fff', borderRadius: '18px 18px 0 0', width: '100%', maxWidth: 480, padding: '18px 20px 26px' }}>\n            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 14 }}>\n              <span style={{ fontWeight: 800, fontSize: 17 }}>Cr\u00e9er un canal artiste</span>\n              <button onClick={() => setOpen(false)} style={{ background: '#F0F2F5', border: 'none', borderRadius: '50%', width: 34, height: 34, cursor: 'pointer', color: '#65676B', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><HiX size={18} /></button>\n            </div>\n            <input value={name} onChange={e => setName(e.target.value)} placeholder=\"Nom de votre canal artiste\"\n              style={{ width: '100%', padding: '12px 14px', borderRadius: 12, border: '1px solid #E4E6EB', fontSize: 15, marginBottom: 14, outline: 'none' }} />\n            <button onClick={createArtist} disabled={creating} className=\"btn-primary\" style={{ width: '100%', padding: '13px 0', borderRadius: 14, fontSize: 15, fontWeight: 700 }}>\n              {creating ? 'Cr\u00e9ation\u2026' : 'Cr\u00e9er le canal'}\n            </button>\n          </div>\n        </div>\n      )}\n\n      {boostTarget && <BoostOrderModal target={boostTarget} onClose={() => setBoostTarget(null)} />}\n      {shareItem && <ShareModal post={shareItem} onClose={() => setShareItem(null)} />}\n    </div>\n  );\n}\n";
const MODAL_SRC="// src/components/BoostOrderModal.jsx\n// Formulaire de commande de boost (fa\u00e7on Facebook Ads) :\n//   - Dur\u00e9e (jours) \u2192 prix = jours \u00d7 3000 Ar\n//   - Zone pr\u00e9f\u00e9r\u00e9e : point + rayon sur carte (Leaflet/OpenStreetMap)\n//   - Objectif : Messages / Abonn\u00e9s / Vues (n'affecte pas le prix)\n//   - Envoi \u2192 doc Firestore \"boostOrders\" (status:'pending'), l'admin valide/refuse.\nimport { useState, useEffect, useRef } from 'react';\nimport { MapContainer, TileLayer, Marker, Circle, useMapEvents } from 'react-leaflet';\nimport 'leaflet/dist/leaflet.css';\nimport { collection, addDoc, serverTimestamp } from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { useAuth } from '../context/AuthContext';\nimport { HiX, HiCheckCircle, HiChatAlt2, HiUserAdd, HiEye, HiLocationMarker } from 'react-icons/hi';\nimport L from 'leaflet';\n\n// Corrige les ic\u00f4nes par d\u00e9faut de Leaflet (chemins cass\u00e9s par les bundlers) via CDN.\nconst markerIcon = new L.Icon({\n  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',\n  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',\n  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',\n  iconSize: [25, 41], iconAnchor: [12, 41], popupAnchor: [1, -34], shadowSize: [41, 41],\n});\n\nconst PRICE_PER_DAY = 3000;\nconst ANTANANARIVO = { lat: -18.8792, lng: 47.5079 };\n\nconst OBJECTIVES = [\n  { key: 'messages', label: 'Obtenir des messages', desc: 'Incite les gens \u00e0 vous \u00e9crire', icon: HiChatAlt2 },\n  { key: 'followers', label: 'Obtenir des abonn\u00e9s', desc: 'Fait conna\u00eetre votre profil/page', icon: HiUserAdd },\n  { key: 'views', label: 'Obtenir plus de vues', desc: 'Maximise la port\u00e9e du contenu', icon: HiEye },\n];\n\nfunction ClickToPlace({ onPick }) {\n  useMapEvents({ click(e) { onPick(e.latlng); } });\n  return null;\n}\n\nexport default function BoostOrderModal({ target, onClose }) {\n  // target = { type:'post'|'profile'|'shop'|'artist', id, ownerUid, title, thumbnailURL }\n  const { currentUser, userProfile } = useAuth();\n  const [step, setStep] = useState(1); // 1: formulaire, 2: confirmation\n  const [days, setDays] = useState(1);\n  const [objective, setObjective] = useState('views');\n  const [center, setCenter] = useState(ANTANANARIVO);\n  const [radiusKm, setRadiusKm] = useState(10);\n  const [zoneName, setZoneName] = useState('');\n  const [searchingZone, setSearchingZone] = useState(false);\n  const [locating, setLocating] = useState(false);\n  const [submitting, setSubmitting] = useState(false);\n  const [error, setError] = useState('');\n  const mapRef = useRef(null);\n\n  const price = Math.max(1, Number(days) || 1) * PRICE_PER_DAY;\n\n  // Essaie de centrer sur la position de l'utilisateur au premier affichage (facultatif).\n  useEffect(() => {\n    if (!navigator.geolocation) return;\n    setLocating(true);\n    navigator.geolocation.getCurrentPosition(\n      (pos) => { setCenter({ lat: pos.coords.latitude, lng: pos.coords.longitude }); setLocating(false); },\n      () => setLocating(false),\n      { timeout: 4000 }\n    );\n  }, []);\n\n  async function searchZoneName() {\n    const query = zoneName.trim();\n    if (!query || searchingZone) return;\n    setSearchingZone(true);\n    try {\n      const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&limit=1&q=${encodeURIComponent(query)}`);\n      const data = await res.json();\n      if (data && data[0]) setCenter({ lat: parseFloat(data[0].lat), lng: parseFloat(data[0].lon) });\n    } catch (e) { /* silencieux : la carte reste sur la position actuelle */ }\n    setSearchingZone(false);\n  }\n\n  function incDays(delta) {\n    setDays((d) => Math.max(1, (Number(d) || 1) + delta));\n  }\n\n  async function submitOrder() {\n    if (submitting) return;\n    setError('');\n    setSubmitting(true);\n    try {\n      await addDoc(collection(db, 'boostOrders'), {\n        targetType: target.type,\n        targetId: target.id,\n        targetOwnerUid: target.ownerUid || currentUser.uid,\n        targetTitle: target.title || '',\n        targetThumb: target.thumbnailURL || '',\n        requesterUid: currentUser.uid,\n        requesterName: userProfile?.fullName || '',\n        requesterPhoto: userProfile?.photoURL || '',\n        days: Math.max(1, Number(days) || 1),\n        price,\n        objective,\n        zone: { lat: center.lat, lng: center.lng, radiusKm, label: zoneName.trim() || null },\n        status: 'pending',\n        createdAt: serverTimestamp(),\n      });\n      setStep(2);\n    } catch (e) {\n      setError(\"\u00c9chec de l'envoi. R\u00e9essayez.\");\n    }\n    setSubmitting(false);\n  }\n\n  return (\n    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.55)', zIndex: 900, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }} onClick={onClose}>\n      <div onClick={(e) => e.stopPropagation()} style={{ background: 'white', borderRadius: '20px 20px 0 0', width: '100%', maxWidth: 480, maxHeight: '92vh', overflowY: 'auto', fontFamily: 'Poppins' }}>\n\n        {/* Header */}\n        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '16px 18px', borderBottom: '1px solid #E4E6EB', position: 'sticky', top: 0, background: 'white', zIndex: 2 }}>\n          <h3 style={{ fontWeight: 800, fontSize: 17, color: '#050505' }}>\n            {step === 1 ? 'Booster' : 'Commande envoy\u00e9e'}\n          </h3>\n          <button onClick={onClose} style={{ background: '#F0F2F5', border: 'none', borderRadius: '50%', width: 32, height: 32, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n            <HiX size={18} />\n          </button>\n        </div>\n\n        {step === 1 ? (\n          <div style={{ padding: 18 }}>\n            {/* Cible */}\n            {target.title && (\n              <div style={{ display: 'flex', alignItems: 'center', gap: 10, background: '#F7F8FA', borderRadius: 12, padding: '10px 12px', marginBottom: 18 }}>\n                {target.thumbnailURL && <img src={target.thumbnailURL} alt=\"\" style={{ width: 40, height: 40, borderRadius: 8, objectFit: 'cover', flexShrink: 0 }} />}\n                <p style={{ fontSize: 13, color: '#65676B', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{target.title}</p>\n              </div>\n            )}\n\n            {/* Objectif */}\n            <p style={{ fontWeight: 700, fontSize: 14, marginBottom: 10 }}>Objectif</p>\n            <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginBottom: 22 }}>\n              {OBJECTIVES.map((o) => (\n                <button key={o.key} onClick={() => setObjective(o.key)}\n                  style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 14px', borderRadius: 14, border: objective === o.key ? '2px solid #1877F2' : '1.5px solid #E4E6EB', background: objective === o.key ? '#EBF2FF' : 'white', cursor: 'pointer', textAlign: 'left' }}>\n                  <o.icon size={20} color={objective === o.key ? '#1877F2' : '#65676B'} style={{ flexShrink: 0 }} />\n                  <div style={{ flex: 1, minWidth: 0 }}>\n                    <p style={{ fontWeight: 700, fontSize: 14, color: '#050505' }}>{o.label}</p>\n                    <p style={{ fontSize: 12, color: '#65676B' }}>{o.desc}</p>\n                  </div>\n                  {objective === o.key && <HiCheckCircle size={18} color=\"#1877F2\" style={{ flexShrink: 0 }} />}\n                </button>\n              ))}\n            </div>\n\n            {/* Dur\u00e9e */}\n            <p style={{ fontWeight: 700, fontSize: 14, marginBottom: 10 }}>Dur\u00e9e</p>\n            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 18, marginBottom: 6 }}>\n              <button onClick={() => incDays(-1)} style={{ width: 40, height: 40, borderRadius: '50%', border: '1.5px solid #E4E6EB', background: 'white', fontSize: 20, fontWeight: 700, cursor: 'pointer', color: '#1877F2' }}>\u2212</button>\n              <div style={{ textAlign: 'center', minWidth: 80 }}>\n                <p style={{ fontSize: 28, fontWeight: 800 }}>{days}</p>\n                <p style={{ fontSize: 12, color: '#65676B' }}>jour{days > 1 ? 's' : ''}</p>\n              </div>\n              <button onClick={() => incDays(1)} style={{ width: 40, height: 40, borderRadius: '50%', border: '1.5px solid #E4E6EB', background: 'white', fontSize: 20, fontWeight: 700, cursor: 'pointer', color: '#1877F2' }}>+</button>\n            </div>\n            <p style={{ textAlign: 'center', fontSize: 13, color: '#65676B', marginBottom: 20 }}>{PRICE_PER_DAY.toLocaleString()} Ar / jour</p>\n\n            {/* Zone pr\u00e9f\u00e9r\u00e9e */}\n            <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 10 }}>\n              <HiLocationMarker size={16} color=\"#65676B\" />\n              <p style={{ fontWeight: 700, fontSize: 14 }}>Zone pr\u00e9f\u00e9r\u00e9e</p>\n              {locating && <span style={{ fontSize: 11, color: '#65676B' }}>(localisation\u2026)</span>}\n            </div>\n            <p style={{ fontSize: 12, color: '#65676B', marginBottom: 10 }}>Touchez la carte, ou tapez un nom de lieu (ex : Madagascar, Mahajanga, Maurice).</p>\n            <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>\n              <input value={zoneName} onChange={(e) => setZoneName(e.target.value)}\n                onKeyDown={(e) => e.key === 'Enter' && searchZoneName()}\n                placeholder=\"Ex : Antananarivo, Mahajanga, Maurice\u2026\"\n                style={{ flex: 1, padding: '10px 12px', borderRadius: 10, border: '1.5px solid #E4E6EB', fontSize: 13, outline: 'none' }} />\n              <button onClick={searchZoneName} disabled={searchingZone || !zoneName.trim()}\n                style={{ padding: '0 16px', borderRadius: 10, border: 'none', background: searchingZone ? '#93B8F5' : '#1877F2', color: 'white', fontWeight: 700, fontSize: 13, cursor: zoneName.trim() ? 'pointer' : 'default' }}>\n                {searchingZone ? '\u2026' : 'Chercher'}\n              </button>\n            </div>\n            <div style={{ borderRadius: 14, overflow: 'hidden', border: '1.5px solid #E4E6EB', marginBottom: 12 }}>\n              <MapContainer center={[center.lat, center.lng]} zoom={11} style={{ height: 220, width: '100%' }} ref={mapRef}>\n                <TileLayer attribution='&copy; OpenStreetMap' url=\"https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png\" />\n                <Marker position={[center.lat, center.lng]} icon={markerIcon} />\n                <Circle center={[center.lat, center.lng]} radius={radiusKm * 1000} pathOptions={{ color: '#1877F2', fillColor: '#1877F2', fillOpacity: 0.15 }} />\n                <ClickToPlace onPick={(latlng) => setCenter({ lat: latlng.lat, lng: latlng.lng })} />\n              </MapContainer>\n            </div>\n            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 22 }}>\n              <span style={{ fontSize: 12, color: '#65676B', flexShrink: 0 }}>Rayon</span>\n              <input type=\"range\" min=\"1\" max=\"100\" value={radiusKm} onChange={(e) => setRadiusKm(Number(e.target.value))} style={{ flex: 1 }} />\n              <span style={{ fontSize: 12, fontWeight: 700, color: '#1877F2', flexShrink: 0, minWidth: 50, textAlign: 'right' }}>{radiusKm} km</span>\n            </div>\n\n            {error && <p style={{ color: '#ef4444', fontSize: 13, marginBottom: 12, textAlign: 'center' }}>{error}</p>}\n\n            {/* R\u00e9cap + envoi */}\n            <div style={{ background: '#F7F8FA', borderRadius: 14, padding: '14px 16px', marginBottom: 16 }}>\n              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>\n                <span style={{ fontSize: 13, color: '#65676B' }}>Dur\u00e9e</span>\n                <span style={{ fontSize: 13, fontWeight: 700 }}>{days} jour{days > 1 ? 's' : ''}</span>\n              </div>\n              <div style={{ display: 'flex', justifyContent: 'space-between' }}>\n                <span style={{ fontSize: 14, fontWeight: 800 }}>Total \u00e0 payer</span>\n                <span style={{ fontSize: 18, fontWeight: 800, color: '#1877F2' }}>{price.toLocaleString()} Ar</span>\n              </div>\n            </div>\n\n            <button onClick={submitOrder} disabled={submitting}\n              style={{ width: '100%', padding: '14px 0', borderRadius: 25, border: 'none', background: submitting ? '#93B8F5' : 'linear-gradient(135deg,#1B84FF,#1877F2)', color: 'white', fontWeight: 800, fontSize: 15, cursor: submitting ? 'wait' : 'pointer', boxShadow: '0 4px 16px rgba(24,119,242,.35)' }}>\n              {submitting ? 'Envoi\u2026' : \"Envoyer \u00e0 l'administrateur\"}\n            </button>\n          </div>\n        ) : (\n          <div style={{ padding: '30px 24px', textAlign: 'center' }}>\n            <div style={{ width: 70, height: 70, borderRadius: '50%', background: '#EBF9F1', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px' }}>\n              <HiCheckCircle size={38} color=\"#16a34a\" />\n            </div>\n            <p style={{ fontWeight: 800, fontSize: 17, marginBottom: 8 }}>Commande envoy\u00e9e !</p>\n            <p style={{ fontSize: 14, color: '#65676B', lineHeight: 1.6, marginBottom: 24 }}>\n              Votre demande de boost ({days} jour{days > 1 ? 's' : ''}, {price.toLocaleString()} Ar) est en attente de validation par l'administrateur.\n            </p>\n            <button onClick={onClose} style={{ width: '100%', padding: '13px 0', borderRadius: 25, border: 'none', background: '#F0F2F5', color: '#050505', fontWeight: 700, fontSize: 14, cursor: 'pointer' }}>\n              Fermer\n            </button>\n          </div>\n        )}\n      </div>\n    </div>\n  );\n}\n";

const fs = require('fs');
let OK = 0, SKIP = 0, FAIL = 0;
const ok = (m) => { OK++; console.log('OK ' + m); };
const skip = (m) => { SKIP++; console.log('SKIP ' + m); };
const fail = (m) => { FAIL++; console.log('FAIL ' + m); };

try {
  const p = 'src/pages/Shop.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('HiLightningBolt')) skip('Shop.jsx : icone Booster deja presente');
  else { fs.writeFileSync(p, SHOP_SRC); ok('Shop.jsx : icone bleu Booster (coin de carte, proprietaire)'); }
} catch (e) { fail('Shop.jsx: ' + e.message); }

try {
  const p = 'src/pages/Artists.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('BoostOrderModal')) skip('Artists.jsx : menu TrackCard deja mis a jour');
  else { fs.writeFileSync(p, ARTISTS_SRC); ok('Artists.jsx : menu complet sur les cartes musique (Informations/Telecharger/Booster/Partager/Supprimer)'); }
} catch (e) { fail('Artists.jsx: ' + e.message); }

try {
  const p = 'src/components/BoostOrderModal.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('searchZoneName')) skip('BoostOrderModal.jsx : recherche de zone deja presente');
  else { fs.writeFileSync(p, MODAL_SRC); ok('BoostOrderModal.jsx : recherche de zone par nom (Madagascar, Mahajanga, Maurice...)'); }
} catch (e) { fail('BoostOrderModal.jsx: ' + e.message); }

console.log('\nRESUME: OK=' + OK + ' SKIP=' + SKIP + ' FAIL=' + FAIL);
